#include <bits/stdc++.h>
using namespace std;
int n,m=0,a[101],sum=0;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];m+=a[i];
    }
    m/=n;
    for(int i=1;i<n;i++){
        if(a[i]<m){
            a[i+1]-=m-a[i];
            a[i]=m;
            sum++;
        }
        else if(a[i]>m){
            a[i+1]+=a[i]-m;
            a[i]=m;
            sum++;
        }
    }
    cout<<sum;
    return 0;
}
